"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[166],{3168:function(e,o){o.Z={id:"chapter-4-2",subject:"science",title:"4.2 Light & Matter",emoji:"\uD83D\uDD26",description:"Learn everything about how light interacts with different objects — and how to stay safe in the sun!",objectives:["\uD83D\uDC41️ How we see objects","\uD83E\uDEA8 Opaque & Shadows","\uD83E\uDE9F Transparent","\uD83C\uDF2B️ Translucent","☀️ Sun Safety","\uD83C\uDF08 Colors of Light"],concepts:[{id:"how-we-see",title:"How Light Lets Us See",subtitle:"Light reflects off objects into your eyes",emoji:"\uD83D\uDCA1",color:"blue",explanation:"Imagine you're reading a book with a lamp on. The lamp sends out light. That light hits the book and <strong>bounces back</strong> (reflects) into your eyes. That's how you see things that don't glow on their own!\n\nWhen light hits any object, <strong>3 things can happen</strong>: it can bounce back (reflect), be soaked up (absorbed), or bend through (refract). Often all three happen at once!",demoType:"seeDemo",lightInteractions:[{emoji:"\uD83E\uDE9E",label:"Reflected",color:"blue",description:"Light bounces back off the surface"},{emoji:"\uD83D\uDD25",label:"Absorbed",color:"coral",description:"Light is soaked into the object"},{emoji:"〰️",label:"Refracted",color:"purple",description:"Light bends as it passes through"}],examples:[]},{id:"opaque",title:"Opaque",subtitle:"Light CANNOT pass through → Shadow forms!",emoji:"\uD83E\uDEA8",color:"grey",explanation:"<strong>Opaque</strong> objects block ALL light. They only reflect or absorb it. Because no light gets through, a dark shape called a <strong>shadow</strong> forms on the other side!\n\nYour body is opaque. That's why you cast a shadow on a sunny day. Thick wood, aluminum foil, and cardboard are all opaque.",demoType:"opaque",examples:[{emoji:"\uD83E\uDE9F",label:"Wooden door"},{emoji:"\uD83E\uDDF1",label:"Brick wall"},{emoji:"\uD83C\uDF2B️",label:"Aluminum foil"},{emoji:"\uD83D\uDCDA",label:"Thick cardboard"},{emoji:"\uD83E\uDDCD",label:"Your body!"}]},{id:"transparent",title:"Transparent",subtitle:"Light passes through FULLY → you see clearly",emoji:"\uD83E\uDE9F",color:"teal",explanation:"<strong>Transparent</strong> objects let ALL the light pass straight through them. You can see what's on the other side perfectly clearly. No shadow is formed because light passes right through!",demoType:"transparent",examples:[{emoji:"\uD83E\uDE9F",label:"Glass window"},{emoji:"\uD83D\uDCA7",label:"Water"},{emoji:"\uD83E\uDDF4",label:"Clear plastic bottle"},{emoji:"\uD83C\uDF2C️",label:"Air"},{emoji:"\uD83D\uDD2D",label:"Eyeglasses lens"}]},{id:"translucent",title:"Translucent",subtitle:"SOME light passes through → things look blurry",emoji:"\uD83C\uDF2B️",color:"purple",explanation:"<strong>Translucent</strong> objects are in between opaque and transparent. They let <strong>some</strong> light through but block the rest. The light that gets through is scattered, making things on the other side look <strong>blurry</strong>.",demoType:"translucent",examples:[{emoji:"\uD83D\uDCC4",label:"Wax paper"},{emoji:"\uD83D\uDEBF",label:"Frosted glass"},{emoji:"\uD83C\uDFA8",label:"Colored tissue paper"},{emoji:"\uD83E\uDDEA",label:"Some plastics"}]},{id:"sun-safety",title:"Sun Safety",subtitle:"Protect your eyes and skin from the sun",emoji:"☀️",color:"yellow",explanation:"Sunlight can <strong>harm your eyes</strong> and cause <strong>sunburn on your skin</strong>. Always protect yourself on hot, sunny days! There are 3 great ways to stay safe:",demoType:"sunSafety",sunSafetyCards:[{emoji:"\uD83D\uDD76️",title:"Sunglasses",description:"Protect your eyes from harmful sunlight rays. Never look directly at the sun!"},{emoji:"\uD83E\uDDF4",title:"Sunscreen",description:"Apply on your skin before going outside. Prevents painful sunburns!"},{emoji:"\uD83E\uDDE2",title:"Hat & Shade",description:"A hat covers your head and face. Sitting in the shade also keeps you cool and safe!"}],examples:[]},{id:"colors-of-light",title:"Colors of Light",subtitle:"Sunlight is a mix of ALL colors!",emoji:"\uD83C\uDF08",color:"teal",explanation:"<strong>Sunlight looks white</strong>, but it's actually a mixture of ALL the colors of the rainbow! When light hits an object, the object <strong>absorbs</strong> some colors and <strong>reflects</strong> others. The color you see is the one that bounces back to your eyes!",demoType:"color",fruitCards:[{emoji:"\uD83C\uDF4B",name:"Yellow Lemon",description:"Reflects <strong>yellow</strong> light. Absorbs all other colors.",tagLabel:"Reflects Yellow",tagColor:"#F0D060",tagBg:"rgba(240,208,96,0.2)"},{emoji:"\uD83C\uDF4F",name:"Green Lime",description:"Reflects <strong>green</strong> light. Absorbs all other colors.",tagLabel:"Reflects Green",tagColor:"#3FB950",tagBg:"rgba(63,185,80,0.2)"},{emoji:"⬜",name:"White Object",description:"Reflects <strong>ALL</strong> colors of light back to your eyes.",tagLabel:"Reflects All",tagColor:"#475569",tagBg:"rgba(100,116,139,0.12)"},{emoji:"⬛",name:"Black Object",description:"Absorbs <strong>ALL</strong> colors. Reflects none back to you.",tagLabel:"Absorbs All",tagColor:"#334155",tagBg:"rgba(30,41,59,0.08)"}],examples:[]}],flashcards:[{emoji:"\uD83E\uDEA8",word:"OPAQUE",color:"#90A4AE",bgFront:"rgba(96,125,139,0.12)",borderFront:"rgba(96,125,139,0.3)",bgBack:"rgba(96,125,139,0.18)",borderBack:"rgba(96,125,139,0.4)",definition:"Light <strong>CANNOT</strong> pass through. Makes a <strong>shadow</strong>!",example:"\uD83E\uDEA8 Wood, foil, cardboard, your body"},{emoji:"\uD83E\uDE9F",word:"TRANSPARENT",color:"#0891B2",bgFront:"rgba(79,195,247,0.08)",borderFront:"rgba(79,195,247,0.3)",bgBack:"rgba(79,195,247,0.12)",borderBack:"rgba(79,195,247,0.4)",definition:"Light passes through <strong>FULLY</strong>. See clearly!",example:"\uD83E\uDE9F Glass, water, clear plastic"},{emoji:"\uD83C\uDF2B️",word:"TRANSLUCENT",color:"#7C3AED",bgFront:"rgba(188,140,255,0.08)",borderFront:"rgba(188,140,255,0.3)",bgBack:"rgba(188,140,255,0.12)",borderBack:"rgba(188,140,255,0.4)",definition:"<strong>SOME</strong> light passes. Things look <strong>blurry</strong>!",example:"\uD83C\uDF2B️ Wax paper, frosted glass"},{emoji:"\uD83C\uDF11",word:"SHADOW",color:"#D97706",bgFront:"rgba(240,208,96,0.08)",borderFront:"rgba(240,208,96,0.3)",bgBack:"rgba(240,208,96,0.12)",borderBack:"rgba(240,208,96,0.4)",definition:"Dark shape formed when an <strong>opaque</strong> object blocks light!",example:"\uD83C\uDF11 Your shadow on a sunny day"}],comparison:{columns:[{emoji:"\uD83E\uDEA8",title:"OPAQUE",color:"#90A4AE",bgColor:"rgba(96,125,139,0.1)",descriptions:["No light passes","Shadow forms","Can't see through"]},{emoji:"\uD83E\uDE9F",title:"TRANSPARENT",color:"#0891B2",bgColor:"rgba(79,195,247,0.06)",descriptions:["All light passes","No shadow","See clearly"]},{emoji:"\uD83C\uDF2B️",title:"TRANSLUCENT",color:"#7C3AED",bgColor:"rgba(188,140,255,0.06)",descriptions:["Some light passes","Faint shadow","See blurry"]}]},quiz:[{q:"What do we call objects that do NOT let any light pass through them?",emoji:"\uD83E\uDEA8",opts:["Transparent","Translucent","Opaque","Shadow"],ans:2,fb:"Opaque objects block ALL light — that's exactly why they create shadows behind them!"},{q:"When an opaque object blocks light, what dark shape forms on the other side?",emoji:"\uD83C\uDF11",opts:["A rainbow","A shadow","A reflection","A beam"],ans:1,fb:"A shadow forms when light can't pass through an opaque object! The area behind gets no light."},{q:"Glass windows, water, and clear plastic are examples of which type of object?",emoji:"\uD83E\uDE9F",opts:["Opaque","Translucent","Shadow","Transparent"],ans:3,fb:"Transparent objects let ALL light pass through — you can see clearly through them!"},{q:"You look at a book through wax paper. The book looks BLURRY. Wax paper is...",emoji:"\uD83D\uDCD6",opts:["Transparent","Opaque","Translucent","Reflective"],ans:2,fb:"Translucent = some light passes, some is blocked → things always look blurry through it!"},{q:"How do we see objects like a book that don't make their own light?",emoji:"\uD83D\uDC41️",opts:["Books glow in the dark","Light bounces off the book into our eyes","Our eyes send out light beams","We can only see them in daylight"],ans:1,fb:"Light reflects (bounces) off objects and travels to our eyes — that's how we see!"},{q:"Which of these is an OPAQUE object?",emoji:"\uD83E\uDD14",opts:["Clear glass","Water","Aluminum foil","Air"],ans:2,fb:"Aluminum foil is opaque — it blocks ALL light! That's why you can't see through it."},{q:"What are THREE ways to stay safe in the sun?",emoji:"☀️",opts:["Sunglasses, sunscreen, and a hat","Dark glasses, water, and jumping","Sunscreen, eating, and sleeping","A hat, swimming, and staying awake"],ans:0,fb:"Sunglasses protect eyes, sunscreen protects skin, and a hat gives shade from the sun!"},{q:"Frosted glass lets SOME light through but things look blurry. Frosted glass is...",emoji:"\uD83E\uDDCA",opts:["Opaque","Transparent","Translucent","Invisible"],ans:2,fb:"Frosted glass is translucent — it only lets part of the light through, making things blurry!"},{q:"Sunlight is actually a mixture of...",emoji:"\uD83C\uDF08",opts:["Just yellow and white light","All the different colors of light","Only red, blue, and green","Heat and electricity"],ans:1,fb:"Sunlight contains ALL colors mixed together — that's why a prism creates a rainbow!"},{q:"Why does a green lime LOOK green?",emoji:"\uD83C\uDF4F",opts:["It absorbs green light and reflects all others","It reflects green light and absorbs all other colors","It makes its own green light","All fruits are green"],ans:1,fb:"Objects look the color they REFLECT! The lime reflects green and absorbs every other color."}],worksheet:{wordBank:["opaque","shadow","transparent","translucent","reflected"],fillBlanks:[{num:1,before:"A wooden door is",after:"because light cannot pass through it."},{num:2,before:"A glass window is",after:"because light passes through it fully."},{num:3,before:"Wax paper is",after:"because only some light passes through it."},{num:4,before:"When an opaque object blocks light, a dark",after:"is formed."},{num:5,before:"We can see objects because light is",after:"off them into our eyes."}],classify:{objects:["glass window","aluminum foil","wax paper","wooden door","clear water bottle","frosted glass"],categories:[{title:"OPAQUE",borderColor:"#90A4AE",titleColor:"#546E7A",count:2},{title:"TRANSPARENT",borderColor:"#4FC3F7",titleColor:"#0277BD",count:2},{title:"TRANSLUCENT",borderColor:"#CE93D8",titleColor:"#6A1B9A",count:2}]},trueOrFalse:[{num:1,statement:"Aluminum foil is transparent. You can see through it."},{num:2,statement:"A shadow forms when light passes completely through an object."},{num:3,statement:"Sunglasses, sunscreen, and hats help protect us from the sun."},{num:4,statement:"Sunlight is a mixture of all the different colors of light."},{num:5,statement:"Frosted glass is translucent — things look blurry through it."}],shortAnswer:[{num:1,question:"How do we see objects that don't make their own light?",points:1,lines:2},{num:2,question:"Name 3 ways to stay safe in sunlight.",points:3,lines:3}],answerKey:{fillBlanks:["opaque","transparent","translucent","shadow","reflected"],classify:{OPAQUE:["aluminum foil","wooden door"],TRANSPARENT:["glass window","clear water bottle"],TRANSLUCENT:["wax paper","frosted glass"]},trueOrFalse:[!1,!1,!0,!0,!0],shortAnswer:["Light bounces (reflects) off objects into our eyes","Sunglasses, sunscreen, hat/shade"]}}}},3947:function(e,o){o.Z={id:"chapter-4-3",subject:"science",title:"4.3 Sound",emoji:"\uD83D\uDD0A",description:"Discover how sound is made, how it travels through air, and how to protect your ears!",objectives:["\uD83C\uDFB8 How sound is made","\uD83C\uDF0A How sound travels","\uD83D\uDD09 Volume (loud & soft)","\uD83C\uDFB5 Pitch (high & low)","\uD83E\uDDF1 Sound through materials","\uD83D\uDEE1️ Protecting your hearing"],concepts:[{id:"making-sounds",title:"How Sound Is Made",subtitle:"Objects vibrate to create sound",emoji:"\uD83C\uDFB8",color:"blue",explanation:"Sound is made when objects <strong>vibrate</strong> — that means they move back and forth very quickly. Both living and non-living things can make sounds. People and some animals can make sounds too! Musical instruments make sounds when they are played.\n\nWhen you pluck a guitar string, it vibrates. When you hit a drum, the drum skin vibrates. These <strong>vibrations</strong> create sound!",demoType:"vibration",examples:[{emoji:"\uD83C\uDFB8",label:"Guitar string"},{emoji:"\uD83E\uDD41",label:"Drum skin"},{emoji:"\uD83D\uDDE3️",label:"Your voice box"},{emoji:"\uD83D\uDCF1",label:"Phone speaker"},{emoji:"\uD83D\uDD14",label:"Bell ringing"}]},{id:"how-sound-travels",title:"How Sound Travels",subtitle:"Sound waves move through the air to your ears",emoji:"\uD83C\uDF0A",color:"teal",explanation:"You hear sounds with your <strong>ears</strong>. When something vibrates, the air around it vibrates too. You hear sound because <strong>air molecules</strong> bump into each other and carry the vibration to your ears.\n\nA <strong>loudspeaker</strong> vibrates when it is turned on. The air around the speaker also vibrates. Parts inside your ear vibrate and you hear the sound of the speaker.",demoType:"soundWave",examples:[{emoji:"\uD83D\uDC42",label:"Your ears"},{emoji:"\uD83D\uDCE2",label:"Loudspeaker"},{emoji:"\uD83D\uDCA8",label:"Air molecules"},{emoji:"\uD83D\uDD14",label:"Vibrating bell"}]},{id:"volume",title:"Volume",subtitle:"How loud or soft a sound is",emoji:"\uD83D\uDD09",color:"coral",explanation:"<strong>Volume</strong> is how loud or soft a sound is. It takes a lot of energy to make a <strong>loud</strong> sound. A loud sound has stronger vibrations. A whisper is a <strong>soft</strong> sound with weaker vibrations.\n\nA hard knock makes a <strong>loud</strong> sound. A gentle tap makes a <strong>soft</strong> sound. The harder you hit something, the louder the sound!",demoType:"volume",examples:[{emoji:"\uD83D\uDCE2",label:"Horn (loud)"},{emoji:"\uD83E\uDD2B",label:"Whisper (soft)"},{emoji:"⏰",label:"Alarm (loud)"},{emoji:"\uD83C\uDFB5",label:"Humming (soft)"}]},{id:"pitch",title:"Pitch",subtitle:"How high or low a sound is",emoji:"\uD83C\uDFB5",color:"purple",explanation:"<strong>Pitch</strong> is how high or low a sound is. When matter vibrates <strong>fast</strong>, it makes <strong>high</strong> sounds. When matter vibrates <strong>slowly</strong>, it makes <strong>low</strong> sounds.\n\n<strong>Small</strong> objects vibrate faster and make <strong>high-pitch</strong> sounds. <strong>Large</strong> objects vibrate more slowly and make <strong>low-pitch</strong> sounds. A small xylophone bar makes a high sound. A big drum makes a low sound.",demoType:"pitch",examples:[{emoji:"\uD83D\uDC26",label:"Bird chirp (high)"},{emoji:"\uD83E\uDD81",label:"Lion roar (low)"},{emoji:"\uD83C\uDFB9",label:"Small key (high)"},{emoji:"\uD83C\uDFB9",label:"Big key (low)"}]},{id:"where-sound-travels",title:"Where Sound Travels",subtitle:"Sound travels through solids, liquids, and gases",emoji:"\uD83E\uDDF1",color:"yellow",explanation:"Sound travels through different kinds of <strong>matter</strong>. Sound can travel through <strong>solids</strong> (like a table or door), <strong>liquids</strong> (like water), and <strong>gases</strong> (like air).\n\nWhales talk to each other through water! You can hear sounds through a closed door because sound travels through the solid wood. When you talk, sound travels through the <strong>air</strong> (a gas) to reach someone's ears.",demoType:"soundTravel",sunSafetyCards:[{emoji:"\uD83E\uDDF1",title:"Through Solids",description:"Sound travels through walls, doors, tables, and floors. Put your ear on a table and tap it!"},{emoji:"\uD83D\uDCA7",title:"Through Liquids",description:"Sound travels through water. Whales and dolphins talk underwater!"},{emoji:"\uD83D\uDCA8",title:"Through Gases",description:"Sound travels through air. This is how you hear someone talking to you!"}],examples:[]},{id:"protecting-hearing",title:"Protecting Your Hearing",subtitle:"Keep your ears safe from loud sounds",emoji:"\uD83D\uDEE1️",color:"grey",explanation:"Very loud sounds can be <strong>dangerous</strong>. They can hurt your ears and even damage your hearing! You should <strong>protect</strong> your hearing:\n\nEarplugs help lower the volume of sounds. People who work near loud machines, like at construction sites, wear <strong>ear protection</strong>. Don't listen to very loud music for too long!",demoType:"none",sunSafetyCards:[{emoji:"\uD83D\uDD07",title:"Earplugs",description:"Wear earplugs at concerts or near loud machines to protect your ears."},{emoji:"\uD83C\uDFA7",title:"Ear Muffs",description:"Workers at construction sites wear ear muffs to block loud noises."},{emoji:"\uD83D\uDD08",title:"Lower Volume",description:"Keep music and TV volume low. Don't listen to loud sounds for too long!"}],examples:[]}],flashcards:[{emoji:"\uD83C\uDFB8",word:"VIBRATION",color:"#2563EB",bgFront:"rgba(88,166,255,0.12)",borderFront:"rgba(88,166,255,0.3)",bgBack:"rgba(88,166,255,0.18)",borderBack:"rgba(88,166,255,0.4)",definition:"When something moves <strong>back and forth</strong> very quickly. Vibrations make <strong>sound</strong>!",example:"\uD83C\uDFB8 A guitar string vibrates to make music"},{emoji:"\uD83D\uDD09",word:"VOLUME",color:"#EA580C",bgFront:"rgba(234,88,12,0.08)",borderFront:"rgba(234,88,12,0.3)",bgBack:"rgba(234,88,12,0.12)",borderBack:"rgba(234,88,12,0.4)",definition:"How <strong>loud</strong> or <strong>soft</strong> a sound is. More energy = louder!",example:"\uD83D\uDD09 A whisper is soft, a shout is loud"},{emoji:"\uD83C\uDFB5",word:"PITCH",color:"#7C3AED",bgFront:"rgba(188,140,255,0.08)",borderFront:"rgba(188,140,255,0.3)",bgBack:"rgba(188,140,255,0.12)",borderBack:"rgba(188,140,255,0.4)",definition:"How <strong>high</strong> or <strong>low</strong> a sound is. Fast vibration = high pitch!",example:"\uD83C\uDFB5 A bird chirp is high, a drum is low"},{emoji:"\uD83C\uDF0A",word:"SOUND WAVE",color:"#0891B2",bgFront:"rgba(79,195,247,0.08)",borderFront:"rgba(79,195,247,0.3)",bgBack:"rgba(79,195,247,0.12)",borderBack:"rgba(79,195,247,0.4)",definition:"Vibrations that travel through <strong>air</strong> (or other matter) to your ears!",example:"\uD83C\uDF0A Sound waves carry music to your ears"}],comparison:{columns:[{emoji:"\uD83D\uDD0A",title:"LOUD",color:"#EA580C",bgColor:"rgba(234,88,12,0.06)",descriptions:["Strong vibrations","Lots of energy","e.g. Alarm, horn"]},{emoji:"\uD83E\uDD2B",title:"SOFT",color:"#0891B2",bgColor:"rgba(79,195,247,0.06)",descriptions:["Weak vibrations","Little energy","e.g. Whisper, hum"]},{emoji:"\uD83C\uDFB5",title:"HIGH vs LOW",color:"#7C3AED",bgColor:"rgba(188,140,255,0.06)",descriptions:["Fast vibration = high","Slow vibration = low","Small = high, Big = low"]}]},quiz:[{q:"What happens when an object vibrates?",emoji:"\uD83C\uDFB8",opts:["It changes color","It makes a sound","It disappears","It gets bigger"],ans:1,fb:"When objects vibrate (move back and forth quickly), they create sound waves!"},{q:"How does sound travel from a speaker to your ears?",emoji:"\uD83C\uDF0A",opts:["Through a wire","Through light beams","Through vibrating air molecules","Sound cannot travel through air"],ans:2,fb:"Sound waves travel through the air! Air molecules bump into each other and carry the vibrations to your ears."},{q:"What is VOLUME?",emoji:"\uD83D\uDD09",opts:["How fast a sound is","How loud or soft a sound is","How high or low a sound is","How far a sound travels"],ans:1,fb:"Volume means how loud or soft a sound is. More energy makes a louder sound!"},{q:"What makes a LOUD sound?",emoji:"\uD83D\uDD0A",opts:["Weak vibrations with little energy","No vibrations at all","Strong vibrations with lots of energy","Slow vibrations"],ans:2,fb:"Loud sounds are made by strong vibrations that use a lot of energy!"},{q:"What is PITCH?",emoji:"\uD83C\uDFB5",opts:["How loud or soft a sound is","How high or low a sound is","How fast sound travels","How far sound goes"],ans:1,fb:"Pitch is how high or low a sound is. Fast vibrations make high pitch, slow vibrations make low pitch."},{q:"A small xylophone bar makes what kind of sound?",emoji:"\uD83C\uDFB9",opts:["A low-pitch sound","A soft sound","A high-pitch sound","No sound at all"],ans:2,fb:"Small objects vibrate faster and make high-pitch sounds! A small xylophone bar sounds higher than a big one."},{q:"Sound can travel through which of these?",emoji:"\uD83E\uDDF1",opts:["Only air","Only water","Solids, liquids, and gases","Only solids"],ans:2,fb:"Sound can travel through all three: solids (like walls), liquids (like water), and gases (like air)!"},{q:"Why can whales hear each other underwater?",emoji:"\uD83D\uDC0B",opts:["They have very big ears","Sound travels through water (a liquid)","They use their eyes instead","Sound cannot travel underwater"],ans:1,fb:"Sound travels through liquids! Whales communicate by sending sound waves through the water."},{q:"Why should you protect your hearing?",emoji:"\uD83D\uDEE1️",opts:["Loud sounds are boring","Very loud sounds can damage your ears","Soft sounds are better for learning","Sound is always dangerous"],ans:1,fb:"Very loud sounds can hurt your ears and damage your hearing! Always protect your ears near loud noises."},{q:"What do earplugs do?",emoji:"\uD83D\uDD07",opts:["Make sounds louder","Make sounds higher","Block or reduce loud sounds to protect your ears","Help you hear better"],ans:2,fb:"Earplugs help lower the volume of sounds reaching your ears, protecting your hearing!"}],worksheet:{wordBank:["vibrate","volume","pitch","sound wave","ears"],fillBlanks:[{num:1,before:"Sound is made when objects",after:"— they move back and forth quickly."},{num:2,before:"How loud or soft a sound is called its",after:"."},{num:3,before:"How high or low a sound is called its",after:"."},{num:4,before:"Vibrations travel through the air as a",after:"to reach your ears."},{num:5,before:"You hear sounds with your",after:"."}],classify:{objects:["whisper","alarm clock","bird chirp","drum beat","lion roar","flute note"],categories:[{title:"LOUD",borderColor:"#EA580C",titleColor:"#C2410C",count:2},{title:"SOFT",borderColor:"#0891B2",titleColor:"#0E7490",count:2},{title:"HIGH PITCH",borderColor:"#7C3AED",titleColor:"#6D28D9",count:2}]},trueOrFalse:[{num:1,statement:"Sound is made when objects vibrate."},{num:2,statement:"Sound cannot travel through water."},{num:3,statement:"A whisper is a loud sound."},{num:4,statement:"Small objects vibrate faster and make high-pitch sounds."},{num:5,statement:"You should protect your ears from very loud sounds."}],shortAnswer:[{num:1,question:"How does sound travel from a guitar to your ears?",points:2,lines:2},{num:2,question:"Name 3 types of matter that sound can travel through. Give an example of each.",points:3,lines:3}],answerKey:{fillBlanks:["vibrate","volume","pitch","sound wave","ears"],classify:{LOUD:["alarm clock","drum beat"],SOFT:["whisper","lion roar"],"HIGH PITCH":["bird chirp","flute note"]},trueOrFalse:[!0,!1,!1,!0,!0],shortAnswer:["The guitar string vibrates, creating sound waves that travel through the air to our ears.","Solids (e.g. wall/door), Liquids (e.g. water), Gases (e.g. air)"]}}}}}]);